using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Good case: Patient retrieves their own EHR document without X-Requester-Id header/// Expected: 200 OK with document content/// </summary>public class EhrServiceTests_GetEhrDocumentSelf_WithValidEhr_ShouldReturnDocument : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetEhrDocumentSelf_WithValidEhr_ShouldReturnDocument()    {        // Authenticate as doctor who can create records        await AuthenticateAsDoctorAsync(EhrClient);        // Step 1: Create an EHR record        var createRequest = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Self access test",                 treatment = "Test treatment",                 notes = "Test notes"             }         };        var createResponse = await PostAsJsonWithRetryAsync(EhrClient, ApiEndpoints.Ehr.CreateRecord, createRequest);        var createJson = await ReadJsonResponseAsync(createResponse);                if (!createJson.TryGetProperty("ehrId", out var ehrIdElement))            return; // Skip if creation fails        var ehrId = Guid.Parse(ehrIdElement.GetString()!);        // Step 2: Get document self (current user access)        var getResponse = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.GetDocumentSelf(ehrId));        // Should succeed or return 403/404 depending on permissions        Assert.True(            getResponse.StatusCode == HttpStatusCode.OK ||             getResponse.StatusCode == HttpStatusCode.Forbidden ||            getResponse.StatusCode == HttpStatusCode.NotFound,            $"Expected 200, 403, or 404, got {getResponse.StatusCode}");    }}